def gen(rng, size):
    budget = [max(1, min(size, 90))]
    def digit():
        budget[0] -= 1
        return str(rng.randint(0, 9))
    def group(depth):
        if budget[0] <= 2 or depth > 20:
            return digit()
        budget[0] -= 2
        return '(' + expr(depth + 1) + ')'
    def expr(depth):
        parts = [group(depth) if rng.random() < 0.6 and budget[0] > 3 else digit()]
        while budget[0] > 3 and rng.random() < 0.5:
            parts.append(rng.choice(['+', '-', '*', '/']))
            parts.append(group(depth) if rng.random() < 0.6 else digit())
        return ''.join(parts)
    s = expr(0)
    if len(s) == 0:
        s = '0'
    return [s]

